SELECT id, username, email, password_digest, bio, avatar_url, created_at, updated_at
FROM users
WHERE id = #{id}

SELECT id, username, email, password_digest, bio, avatar_url, created_at, updated_at
FROM users
WHERE email = #{email}

SELECT COUNT(*) > 0
FROM users
WHERE email = #{email}

SELECT COUNT(*) > 0
FROM users
WHERE username = #{username}
